import React, { useState } from 'react';

const SimplePage = () => {
  const [count, setCount] = useState(0);

  const handleClick = () => {
    setCount(count + 1);
  };

  return (
    <div style={{ padding: '40px', textAlign: 'center', fontFamily: 'Arial, sans-serif' }}>
      <h1>Página Simple en React</h1>
      <p>Botón presionado {count} veces</p>
      <button
        onClick={handleClick}
        style={{
          padding: '10px 20px',
          fontSize: '16px',
          backgroundColor: '#007bff',
          color: 'white',
          border: 'none',
          borderRadius: '5px',
          cursor: 'pointer'
        }}
      >
        Presionar Botón
      </button>
      <a
          href="/landing"
          style={{
            display: 'block',
            textAlign: 'center',
            color: '#007bff',
            textDecoration: 'none',
            fontSize: '14px'
          }}
        >
          Volver a la página principal
        </a>
    </div>
  );
};

export default SimplePage;
